import requests
from dataclasses import dataclass
from datetime import datetime

PAGERDUTY_TOKEN = os.environ["PAGERDUTY_TOKEN"]


@dataclass
class IncidentSummary:
    id: str
    title: str
    severity: str       # P0 | P1 | P2
    started_at: datetime
    resolved_at: datetime
    mttr_minutes: float
    postmortem_url: str | None
    open_action_items: int


def fetch_incidents_for_month(year: int, month: int) -> list[dict]:
    import calendar
    start = datetime(year, month, 1).isoformat() + "Z"
    last_day = calendar.monthrange(year, month)[1]
    end = datetime(year, month, last_day, 23, 59, 59).isoformat() + "Z"
    resp = requests.get(
        "https://api.pagerduty.com/incidents",
        headers={
            "Authorization": f"Token token={PAGERDUTY_TOKEN}",
            "Accept": "application/vnd.pagerduty+json;version=2",
        },
        params={
            "since": start,
            "until": end,
            "statuses[]": ["resolved"],
            "limit": 100,
        },
        timeout=15,
    )
    resp.raise_for_status()
    return resp.json().get("incidents", [])


def compute_mttr(incidents: list[dict]) -> dict:
    by_severity: dict[str, list[float]] = {}
    for inc in incidents:
        created = datetime.fromisoformat(inc["created_at"].replace("Z", "+00:00"))
        resolved = datetime.fromisoformat(inc["last_status_change_at"].replace("Z", "+00:00"))
        minutes = (resolved - created).total_seconds() / 60
        sev = inc.get("priority", {}).get("name", "P3")
        by_severity.setdefault(sev, []).append(minutes)
    return {
        sev: sum(vals) / len(vals) for sev, vals in by_severity.items()
    }
